def solve(nums: Array[Long]): Long = {
  val n = nums.length
  val sortedAbs = nums.map(Math.abs).sorted
  var total = 0L
  for (i <- 0 until n - 1) {
    val target = 2 * sortedAbs(i)
    var left = i + 1
    var right = n - 1
    var res = n
    while (left <= right) {
      val mid = (left + right) / 2
      if (sortedAbs(mid) > target) {
        res = mid
        right = mid - 1
      } else {
        left = mid + 1
      }
    }
    total += (res - (i + 1)).toLong
  }
  total
}
